{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-cross-object-mixed-risk-reconnect-compressor-mixed-parameter-patch-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "partial",
  "requires_confirmation": true,
  "answers": [
    {
      "summary": "当前围绕已选中的压缩机 Recycle Compressor 22、分离器 Intermediate Separator 22，以及未连接的出口物流 Separator Gas 94 生成候选编辑提案；提案仅覆盖有直接诊断支撑的局部参数缺失、参数越界/不一致和下游连接占位问题。",
      "issues": [
        {
          "code": "COMPRESSOR_OUTLET_PRESSURE_TARGET_INVALID",
          "message": "Recycle Compressor 22 的出口压力目标低于入口压力，和当前入口物流 feed-94 的 190 kPa 以及出口物流 compressor-outlet-94 的 172 kPa 状态不一致。",
          "severity": "error",
          "target": {
            "type": "unit",
            "id": "compressor-22"
          },
          "citations": [
            "diag-2",
            "flowdoc-unit-1",
            "flowdoc-stream-1",
            "flowdoc-stream-2",
            "snapshot-1"
          ]
        },
        {
          "code": "COMPRESSOR_MINIMUM_FLOW_BYPASS_MISSING",
          "message": "Recycle Compressor 22 已标记需要 anti-surge review，但缺少 minimum flow bypass percent 参数。",
          "severity": "error",
          "target": {
            "type": "unit",
            "id": "compressor-22"
          },
          "citations": [
            "diag-3",
            "flowdoc-unit-1",
            "snapshot-1"
          ]
        },
        {
          "code": "UNIT_PARAMETER_OUT_OF_RANGE",
          "message": "Recycle Compressor 22 的 efficiency_percent=58 被诊断为超出推荐运行范围，需要人工复核或替换为经确认的效率值。",
          "severity": "warning",
          "target": {
            "type": "unit",
            "id": "compressor-22"
          },
          "citations": [
            "diag-5",
            "flowdoc-unit-1"
          ]
        },
        {
          "code": "UNIT_PARAMETER_INCOMPLETE",
          "message": "Intermediate Separator 22 使用 fixed pressure 模式，但缺少 operating pressure target。",
          "severity": "error",
          "target": {
            "type": "unit",
            "id": "separator-22"
          },
          "citations": [
            "diag-4",
            "flowdoc-unit-2",
            "snapshot-1"
          ]
        },
        {
          "code": "STREAM_DISCONNECTED",
          "message": "Separator Gas 94 没有连接到任何下游 consumer 或 export sink；同时诊断提示其路由依赖当前压缩机排出和分离器压力上下文，因此仅建议添加待确认的连接占位，而不自动重连到具体单元。",
          "severity": "error",
          "target": {
            "type": "stream",
            "id": "separator-gas-94"
          },
          "citations": [
            "diag-1",
            "diag-6",
            "flowdoc-stream-3",
            "snapshot-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 Recycle Compressor 22 添加需确认的出口压力目标候选值",
          "target": {
            "type": "unit",
            "id": "compressor-22"
          },
          "rationale": "当前压缩机 control_mode 为 outlet_pressure，但 outlet_pressure_target_kpa=165 低于入口物流 feed-94 的 190 kPa，并且低于当前出口物流 compressor-outlet-94 的 172 kPa。为解除直接诊断的不一致，建议把出口压力目标作为待确认参数更新到不低于当前入口压力的候选值；该数值仅为局部候选补丁，需工程确认后应用。",
          "patch": {
            "parameter_updates": {
              "config.outlet_pressure_target_kpa": {
                "from": 165,
                "to": 190,
                "note": "候选值取当前入口压力 feed-94.specs.pressure_kpa；若实际工艺要求压缩升压，应由用户确认更高的目标压力。"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-2",
            "flowdoc-unit-1",
            "flowdoc-stream-1",
            "flowdoc-stream-2",
            "snapshot-1"
          ],
          "confidence": 0.73
        },
        {
          "action": "candidate_edit",
          "title": "为 Recycle Compressor 22 补充最小流量旁路百分比占位参数",
          "target": {
            "type": "unit",
            "id": "compressor-22"
          },
          "rationale": "诊断指出 anti_surge_review_required=true 时缺少 minimum flow bypass percent。由于输入中没有提供设计旁路百分比，建议只添加待填写占位，而不猜测具体数值。",
          "patch": {
            "parameter_placeholders": {
              "config.minimum_flow_bypass_percent": {
                "required": true,
                "value": null,
                "reason": "anti-surge review requires minimum flow bypass percent"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-3",
            "flowdoc-unit-1",
            "snapshot-1"
          ],
          "confidence": 0.86
        },
        {
          "action": "candidate_edit",
          "title": "将 Recycle Compressor 22 的效率参数标记为待复核占位",
          "target": {
            "type": "unit",
            "id": "compressor-22"
          },
          "rationale": "当前 efficiency_percent=58 被诊断为超出推荐运行范围，但请求中没有给出推荐范围或替代效率值。建议保留原值并添加待复核占位，避免凭空替换关键性能参数。",
          "patch": {
            "parameter_placeholders": {
              "config.efficiency_percent_review": {
                "required": true,
                "current_value": 58,
                "reason": "efficiency_percent is outside the recommended operating range"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-5",
            "flowdoc-unit-1"
          ],
          "confidence": 0.68
        },
        {
          "action": "candidate_edit",
          "title": "为 Intermediate Separator 22 补充固定压力目标占位参数",
          "target": {
            "type": "unit",
            "id": "separator-22"
          },
          "rationale": "Intermediate Separator 22 的 pressure_mode 为 fixed，但缺少 operating pressure target。由于当前相关物流给出 compressor-outlet-94 为 172 kPa、separator-gas-94 为 164 kPa，且没有明确分离器设计压力，建议添加待确认占位而不自动推断具体目标。",
          "patch": {
            "parameter_placeholders": {
              "config.operating_pressure_target_kpa": {
                "required": true,
                "value": null,
                "reason": "fixed pressure mode requires an operating pressure target",
                "context_values": {
                  "inlet_stream_pressure_kpa": 172,
                  "gas_outlet_stream_pressure_kpa": 164
                }
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-4",
            "flowdoc-unit-2",
            "flowdoc-stream-2",
            "flowdoc-stream-3",
            "snapshot-1"
          ],
          "confidence": 0.81
        },
        {
          "action": "candidate_edit",
          "title": "为 Separator Gas 94 添加下游连接待定占位",
          "target": {
            "type": "stream",
            "id": "separator-gas-94"
          },
          "rationale": "Separator Gas 94 当前没有 target_unit_id 或导出汇点，导致 invalid_topology。由于另有诊断说明其路由依赖当前压缩机排出和分离器压力上下文，直接重连到某个具体单元或 sink 会显著改变拓扑和求解行为；因此只建议添加需要人工确认的 connection placeholder。",
          "patch": {
            "connection_placeholder": {
              "field": "target_unit_id_or_export_sink",
              "required": true,
              "current_target_unit_id": null,
              "candidate": null,
              "reason": "downstream consumer or export sink is missing; routing is state-dependent"
            }
          },
          "risk_level": "high",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "diag-6",
            "flowdoc-stream-3",
            "snapshot-1"
          ],
          "confidence": 0.76
        }
      ],
      "confidence": 0.76
    }
  ]
}
